values
  ('CORP-E2E-01', array['corp'], 'MF+Worker', 'impl', 'Baja manual de SellerMarketplace → el worker restaura la integración (~10 min)', 'E2E worker + tracking + reconciliación', 'Usuario corporativo con integración activa (ej. Frávega). Acceso a la DB.', 'Borrar la row de SellerMarketplace (Frávega) · esperar el ciclo del worker (300s) hasta 2 vueltas', '["Loguearse (aecom-test@yopmail.com) y ver Panel de Integraciones con Frávega + Cetrogar en Integrado.","Eliminar en la DB la row SellerMarketplace de Frávega. Refrescar: Frávega vuelve a Disponible.","Esperar ~10 min (ciclos del worker). Refrescar."]'::jsonb, '["Tras la baja, Frávega aparece Disponible (integración perdida).","El worker detecta un envío del seller bajo el contrato de Frávega vía tracking hub y re-inserta/reactiva la relación.","La integración vuelve a Integrado sin intervención manual. (Evidencia 07-2026: restauró a los 10 min.)"]'::jsonb, null, true, 0),
  ('MF-AUTH-01-CORP', array['corp'], 'MF', 'impl', 'Bootstrap recibe auth y decide vista (Marketplace vs Seller)', 'Bootstrap / auth (src/bootstrap/App.tsx)', 'MF montado por un shell (o harness standalone) con prop auth válida.', 'auth.marketplaceId truthy → Marketplace · null/"" → Seller', '["Montar con auth.marketplaceId presente.","Repetir con auth.marketplaceId null/vacío."]'::jsonb, '["Con marketplaceId → MarketplacePage (data-testid=\"marketplace-app\").","Sin marketplaceId → SellerPage (data-testid=\"seller-app\").","En ambos, localStorage[\"fullcommerce:token\"] queda con auth.token.token."]'::jsonb, null, false, 1),
  ('MF-AUTH-01-PYME', array['pyme'], 'MF', 'impl', 'Bootstrap recibe auth y decide vista (Marketplace vs Seller)', 'Bootstrap / auth (src/bootstrap/App.tsx)', 'MF montado por un shell (o harness standalone) con prop auth válida.', 'auth.marketplaceId truthy → Marketplace · null/"" → Seller', '["Montar con auth.marketplaceId presente.","Repetir con auth.marketplaceId null/vacío."]'::jsonb, '["Con marketplaceId → MarketplacePage (data-testid=\"marketplace-app\").","Sin marketplaceId → SellerPage (data-testid=\"seller-app\").","En ambos, localStorage[\"fullcommerce:token\"] queda con auth.token.token."]'::jsonb, null, false, 2),
  ('MF-SELLERS-01', array['corp'], 'MF', 'impl', 'Grilla de sellers carga desde API', 'Marketplace Sellers grid', 'Vista Marketplace · token REST válido · API arriba.', 'GET /api/v1/Marketplace/sellers?Page=1&PageSize=10', '["Entrar como marketplace y abrir vista Sellers (KPI \"Sellers totales\").","Observar la request."]'::jsonb, '["Loading: fila con CircularProgress.","Success: filas con nombre + estado (Pills) + paginación server.","Empty: \"No hay sellers para mostrar.\"","Error: \"No pudimos cargar los sellers. Intenta nuevamente.\""]'::jsonb, null, false, 3),
  ('MF-SELLERS-02', array['corp'], 'MF', 'impl', 'Filtro por estado (Activa / Inactiva)', 'Marketplace Sellers grid', 'Grilla cargada.', 'Status=Activa / Status=Inactiva', '["Seleccionar filtro Activa.","Seleccionar Inactiva."]'::jsonb, '["La request incluye Status y refetchea con overlay de loading.","Solo se muestran sellers del estado elegido."]'::jsonb, null, false, 4),
  ('MF-SELLERS-03', array['corp'], 'MF', 'impl', 'Búsqueda + paginación + page size', 'Marketplace Sellers grid', 'Grilla con más de una página.', 'Page size 5 / 10 / 20', '["Buscar un fragmento de nombre/email.","Cambiar page size (5→20).","Navegar entre páginas."]'::jsonb, '["Búsqueda filtra CLIENT-SIDE sobre la página cargada (el server no tiene param Search).","Cambiar page size dispara nueva request.","Paginación avanza/retrocede."]'::jsonb, 'Quirk conocido: durante la búsqueda el count de paginación usa solo el largo filtrado.', false, 5),
