  ('MF-SHIP-01', array['corp'], 'MF', 'impl', 'Grilla de envíos vía SignalR', 'MarketplaceSellerShipments.tsx', 'Branch NTGRCNS-562 · token LARGO B2C en localStorage["token"] · hub de tracking accesible.', 'Hub TrackingSubscribeState · evento sendTracking · seller pruebacorpo24 (94 envíos) · userId="" · 30 días', '["Abrir la vista de envíos de un seller.","Observar: WebSocket (skipNegotiation) → send → sendTracking.","Cambiar el rango Desde."]'::jsonb, '["Conecta por WebSockets directo (sin negotiate).","Muestra hasta 50 filas (cap del hub) + aviso \"Mostrando N de M\".","Cambiar fecha resetea a página 0 y re-suscribe.","userId debe ir VACÍO (el GUID no mapea en el elastic de tracking)."]'::jsonb, 'Vive solo en branch NTGRCNS-562 (PR #25, draft). No está en develop.', false, 12),
  ('MF-SHIP-02', array['corp'], 'MF', 'impl', 'Estados UX de la grilla de envíos (loading / empty / timeout)', 'Grilla de envíos — estados', 'Igual que MF-SHIP-01.', 'Timeout de respuesta (default de useHubSubscription)', '["Cargar con conexión OK pero sin datos (seller sin envíos en la ventana).","Cortar red tras conectar para gatillar el timeout."]'::jsonb, '["Loading: \"Recuperando envíos\".","Empty: mensaje de sin resultados.","Timeout: banner de error (por timeout, no por rechazo de send).","Sin flashes ni doble-suscripción al reconectar."]'::jsonb, 'Vive solo en branch NTGRCNS-562.', false, 13),
