  ('WK-SYNC-01', array['otros'], 'Worker', 'impl', 'Arranque y loop periódico', 'SellerSynchronizationWorker', '.NET 10 · DB de prueba · Worker:ExecutionIntervalSeconds (ej. 5s).', 'dotnet run --project src/Api/ActualizacionSellersWorker.csproj', '["Levantar con intervalo corto.","Observar logs + APM."]'::jsonb, '["Log de deployment marker al iniciar.","Cada iteración abre transacción APM seller-synchronization y loguea el resumen.","Intervalo ≤0 → excepción de config."]'::jsonb, null, false, 32),
  ('WK-SYNC-02', array['otros'], 'Worker', 'impl', 'Carga de contratos activos (Contract ⋈ Marketplace)', 'GetActiveContracts', 'DB con Contract + Marketplace.', 'c.IsDeleted=0 AND m.IsActive=1 AND m.IsDeleted=0', '["Insertar 1 contrato activo + 1 borrado.","Correr una iteración."]'::jsonb, '["Solo el activo entra al procesamiento.","Ventana: to=now, from=now - ActiveSellerLookbackDays (default 30)."]'::jsonb, null, false, 33),
  ('WK-SYNC-03', array['otros'], 'Worker', 'impl', 'Consulta al hub de tracking por contrato', 'TrackingSuscribeStateByContrato', 'Hub accesible (Tracking:HubUrl).', '{idSistema:4, idReceptor:2, contrato, from, to, esActivo:true} · evento SendTrackingByContrato', '["Con un contrato con envíos en la ventana, correr iteración.","Observar suscripción y respuesta."]'::jsonb, '["Recibe resultsList; mapea email→MarketplaceEmail, fechaPrimeraNovedad→LastShipment.","Items con email vacío se descartan.","Dedup por (ContractNo, MarketplaceEmail) con el LastShipment más reciente.","Fallo del hub → contrato cuenta como failed, el loop sigue."]'::jsonb, null, false, 34),
  ('WK-SYNC-04', array['otros'], 'Worker', 'impl', 'Alta de relación Seller-Marketplace nueva', 'SellerMarketplaceReconciler', 'Tracking devuelve un seller sin relación con ese marketplace.', 'Login API POST /api/v1/Usuario/Email para resolver nombre/CL/tipo', '["Preparar tracking con seller nuevo.","Correr iteración."]'::jsonb, '["Resuelve el Seller (por email; si no, reactiva soft-deleted; si no, Login API + insert).","Corporate sin CL resoluble → se saltea.","Inserta/reactiva SellerMarketplace → Registered.","Emails normalizados Trim().ToLowerInvariant()."]'::jsonb, null, false, 35),
  ('WK-SYNC-05', array['otros'], 'Worker', 'impl', 'Update de LastShipment (envío más reciente)', 'UpdateLastShipment (condicional)', 'Existe SellerMarketplace activo con LastShipment viejo.', 'Tracking con envío más reciente / más viejo', '["Envío más nuevo → correr iteración.","Repetir con envío más viejo."]'::jsonb, '["Más nuevo → UPDATE condicional de LastShipment → Updated; si Name vacío, SellerNameEnricher lo completa (best-effort).","Más viejo → SkippedOlderShipment (no actualiza)."]'::jsonb, null, false, 36),
  ('WK-SYNC-06', array['otros'], 'Worker', 'impl', 'Fallback a PendingSellerMarketplace', 'UpsertPendingSellerMarketplace', 'Seller no resoluble o relación ya activa.', '—', '["Forzar un seller no resoluble (corporate sin CL) o relación ya activa.","Correr iteración."]'::jsonb, '["Upsert en PendingSellerMarketplace (insert o update de LastShipment) → QueuedToPending.","No rompe el resto del procesamiento."]'::jsonb, null, false, 37)
